-// ─── Autocorrelation Pitch Detection ─────────────────────────────────────────
-
-function detectPitch(buf, sampleRate) {
-  // RMS check
-  let rms = 0;
-  for (let i = 0; i < buf.length; i++) rms += buf[i] * buf[i];
-  rms = Math.sqrt(rms / buf.length);
-  if (rms < 0.01) return null;
-
-  // Autocorrelation
-  const SIZE = buf.length;
-  const corr = new Float32Array(SIZE);
-  for (let lag = 0; lag < SIZE; lag++) {
-    let s = 0;
-    for (let i = 0; i < SIZE - lag; i++) s += buf[i] * buf[i + lag];
-    corr[lag] = s;
-  }
-
-  // Find first local max after initial dip
-  let d = 0;
-  while (d < SIZE && corr[d] > corr[d+1]) d++;
-  let maxCorr = -1, bestLag = -1;
-  for (let i = d; i < SIZE; i++) {
-    if (corr[i] > maxCorr) { maxCorr = corr[i]; bestLag = i; }
-  }
-  if (bestLag < 2 || maxCorr < corr[0] * 0.5) return null;
-
-  // Parabolic interpolation
-  const y1 = corr[bestLag-1], y2 = corr[bestLag], y3 = corr[bestLag+1];
-  const refinedLag = bestLag + 0.5 * (y1 - y3) / (y1 - 2*y2 + y3 + 1e-10);
-  const freq = sampleRate / refinedLag;
-  if (freq < 60 || freq > 1200) return null;
-  return freq;
-}
